const float psinn_fc4_1_b[1] = {
    1.30348629e-03f
};


/* input = (t, x). The tied weights make u(t,-x) = -u(t,x) hold exactly, in fp32,
   on the device -- the symmetry is structural, not learned. (float32 weights) */
void psinn_forward(const float *in, float *out) {
    const float t = in[0], x = in[1];
    /* static, like the dense kernel's buffers: activation memory must land in .bss so
       that arm-none-eabi-size counts it. Stack-allocated locals are NOT counted by
       `size`, and comparing a stack-allocated kernel against a statically allocated one
       would understate this model's RAM. */
    static float u1_1[PSINN_N], u1_2[PSINN_N];
    static float u2_1[PSINN_N], u2_2[PSINN_N], u2_3[PSINN_N];
    static float u3_1[2 * PSINN_N];
    int i, j;

    for (i = 0; i < PSINN_N; i++) {
        const float a = psinn_fc1_1_w[i] * t + psinn_fc1_1_b[i];
        const float b = psinn_fc1_3_w[i] * x;
        u1_1[i] = tanhf(a + b);
        u1_2[i] = tanhf(a - b);
    }
    for (j = 0; j < PSINN_N; j++) {
        float s1 = 0.0f, s2 = 0.0f, s3 = 0.0f;
        for (i = 0; i < PSINN_N; i++) {
            const float a1 = psinn_fc2_1_w[i * PSINN_N + j];
            const float a2 = psinn_fc2_2_w[i * PSINN_N + j];
            const float a3 = psinn_fc2_3_w[i * PSINN_N + j];
            s1 += u1_1[i] * a1 + u1_2[i] * a3;
            s2 += u1_1[i] * a3 + u1_2[i] * a1;
            s3 += (u1_1[i] - u1_2[i]) * a2;
        }
        const float bb = psinn_fc2_1_b[j] + psinn_fc2_3_b[j];
        u2_1[j] = tanhf(s1 + bb);
        u2_2[j] = tanhf(s2 + bb);
        u2_3[j] = tanhf(s3);
    }
    for (j = 0; j < 2 * PSINN_N; j++) {
        float s = 0.0f;
        for (i = 0; i < PSINN_N; i++) {
            s += (u2_1[i] - u2_2[i]) * psinn_fc3_1_w[i * 2 * PSINN_N + j];
            s += u2_3[i] * psinn_fc3_2_w[i * 2 * PSINN_N + j];
        }
        u3_1[j] = tanhf(s);
    }
    float o = psinn_fc4_1_b[0];
    for (i = 0; i < 2 * PSINN_N; i++) o += u3_1[i] * psinn_fc4_1_w[i];
    out[0] = o;
}
